/**
 * TurnActions — 消息操作栏（同款设计）
 * 每条 AI 回复下方显示：复制 / 新建对话（从当前轮次）
 */

import { useState } from 'react'
import { Copy, Check, Plus } from 'lucide-react'

interface TurnActionsProps {
  text: string
  onFork?: () => void
}

export function TurnActions({ text, onFork }: TurnActionsProps) {
  const [copied, setCopied] = useState(false)

  const handleCopy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true)
      setTimeout(() => setCopied(false), 1500)
    })
  }

  const handleNewFromHere = () => {
    // 保存当前会话，然后新建（保留当前回复作为上下文参考）
    if (onFork) {
      onFork()
    }
  }

  return (
    <div className="flex items-center gap-1 mt-1 ml-1 opacity-0 group-hover:opacity-100 transition-opacity">
      <button
        onClick={handleCopy}
        className="flex items-center gap-1 px-2 py-1 text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-md transition-colors"
        title="复制回复"
      >
        {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
        <span>{copied ? '已复制' : '复制'}</span>
      </button>
      <button
        onClick={handleNewFromHere}
        className="flex items-center gap-1 px-2 py-1 text-xs text-slate-400 hover:text-blue-500 dark:hover:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-md transition-colors"
        title="从这里新建对话"
      >
        <Plus className="w-3 h-3" />
        <span>新建对话</span>
      </button>
    </div>
  )
}
