/**
 * UserBubble 组件
 * 右对齐，蓝色背景，白色文字
 * 增加：附件展示 + 复制按钮 + 时间戳
 */

import { useState } from 'react'
import { Copy, Check, FileText } from 'lucide-react'
import type { Message, Attachment } from '@/types'

interface UserBubbleProps {
  msg: Message
}

function formatTime(ts: number): string {
  const d = new Date(ts)
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${hh}:${mm}`
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
}

function AttachmentPreview({ attachment }: { attachment: Attachment }) {
  if (attachment.previewUrl || attachment.data) {
    return (
      <div className="relative group/att">
        <img
          src={attachment.previewUrl || `data:${attachment.type};base64,${attachment.data}`}
          alt={attachment.name}
          className="max-w-[200px] max-h-[150px] rounded-lg object-cover border border-blue-400/30"
        />
        <div className="absolute bottom-1 left-1 px-1.5 py-0.5 bg-black/50 rounded text-[10px] text-white truncate max-w-[150px]">
          {attachment.name}
        </div>
      </div>
    )
  }

  return (
    <div className="flex items-center gap-2 px-3 py-2 bg-blue-500/20 rounded-lg border border-blue-400/30">
      <FileText className="w-4 h-4 text-blue-200 shrink-0" />
      <div className="min-w-0">
        <p className="text-xs text-blue-100 truncate max-w-[150px]">{attachment.name}</p>
        <p className="text-[10px] text-blue-200/70">{formatSize(attachment.size)}</p>
      </div>
    </div>
  )
}

export function UserBubble({ msg }: UserBubbleProps) {
  const [copied, setCopied] = useState(false)

  const handleCopy = () => {
    navigator.clipboard.writeText(msg.content).then(() => {
      setCopied(true)
      setTimeout(() => setCopied(false), 1500)
    })
  }

  const hasAttachments = msg.attachments && msg.attachments.length > 0

  return (
    <div className="flex justify-end group">
      <div className="max-w-[80%] flex flex-col items-end gap-1">
        {/* 附件展示 */}
        {hasAttachments && (
          <div className="flex flex-wrap gap-2 justify-end">
            {msg.attachments!.map((att) => (
              <AttachmentPreview key={att.id} attachment={att} />
            ))}
          </div>
        )}

        {/* 文本消息 */}
        {msg.content && (
          <div className="rounded-2xl px-4 py-3 bg-blue-600 text-white text-base whitespace-pre-wrap break-words">
            {msg.content}
          </div>
        )}

        {/* 底部信息 */}
        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <span className="text-xs text-slate-400 dark:text-slate-500">
            {formatTime(msg.timestamp)}
          </span>
          <button
            onClick={handleCopy}
            className="flex items-center gap-1 text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors"
            title="复制"
          >
            {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
          </button>
        </div>
      </div>
    </div>
  )
}
