/**
 * AssistantBubble 组件
 * 左对齐，白色背景，带边框
 * 未完成时末尾显示闪烁光标
 * 增加：复制按钮 + 时间戳 + 操作栏
 */

import { useState } from 'react'
import { Copy, Check } from 'lucide-react'
import MarkdownBlock from '@/components/common/MarkdownBlock'
import { TurnActions } from './TurnActions'
import type { Message } from '@/types'

interface AssistantBubbleProps {
  msg: Message
}

function formatTime(ts: number): string {
  const d = new Date(ts)
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${hh}:${mm}`
}

export function AssistantBubble({ msg }: AssistantBubbleProps) {
  const [copied, setCopied] = useState(false)

  const handleCopy = () => {
    navigator.clipboard.writeText(msg.content).then(() => {
      setCopied(true)
      setTimeout(() => setCopied(false), 1500)
    })
  }

  return (
    <div className="flex justify-start group">
      <div className="max-w-[85%]">
        {/* 标题行 */}
        <div className="flex items-center gap-2 mb-1 ml-1">
          <span className="text-xs text-slate-400 dark:text-slate-500">小智</span>
          <span className="text-xs text-slate-300 dark:text-slate-600">
            {formatTime(msg.timestamp)}
          </span>
        </div>

        {/* 消息气泡 */}
        <div className="rounded-2xl px-4 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-600 text-slate-800 dark:text-slate-100 text-base relative">
          <MarkdownBlock markdown={msg.content} showCursor={!msg.finalized} />
          {/* 复制按钮（hover 显示） */}
          {msg.finalized && msg.content && (
            <button
              onClick={handleCopy}
              className="absolute top-2 right-2 flex items-center gap-1 text-xs text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity bg-white dark:bg-slate-700 rounded-lg px-2 py-1 shadow-sm border border-slate-200 dark:border-slate-600"
              title="复制"
            >
              {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />}
              {copied ? '已复制' : '复制'}
            </button>
          )}
        </div>

        {/* 操作栏（完成后显示） */}
        {msg.finalized && msg.content && (
          <TurnActions text={msg.content} />
        )}
      </div>
    </div>
  )
}
